```cpp
#include <iostream>
#include <vector>

class Polynomial {
public:
    std::vector<int> coefficients;

    Polynomial() : coefficients({0}) {}

    void addTerm(int coefficient, int degree) {
        while (degree >= static_cast<int>(coefficients.size())) {
            coefficients.push_back(0);
        }
        coefficients[degree] += coefficient;
    }

    Polynomial derivative() const {
        Polynomial derivativePoly;
        for (size_t i = 1; i < coefficients.size(); ++i) {
            derivativePoly.addTerm(i * coefficients[i], i - 1);
        }
        return derivativePoly;
    }

    void print() const {
        for (size_t i = coefficients.size() - 1; i > 0; --i) {
            if (coefficients[i] != 0) {
                std::cout << coefficients[i] << "x^" << i;
                if (coefficients[i + 1] != 0 || coefficients[i - 1] != 0) {
                    std::cout << " + ";
                }
            }
        }
        if (coefficients[0] != 0) {
            std::cout << coefficients[0];
        }
        std::cout << std::endl;
    }
};

int main() {
    Polynomial poly;

    // Example: Input: 3x^2 + 2x + 1
    poly.addTerm(3, 2);
    poly.addTerm(2, 1);
    poly.addTerm(1, 0);

    std::cout << "Original Polynomial: ";
    poly.print();

    Polynomial derivativePoly = poly.derivative();
    std::cout << "Derivative: ";
    derivativePoly.print();

    return 0;
}
```

